package com.example.traveling;

import android.os.Bundle;
import android.widget.Button;

import androidx.activity.EdgeToEdge;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.graphics.Insets;
import androidx.core.view.ViewCompat;
import androidx.core.view.WindowInsetsCompat;
import androidx.fragment.app.Fragment;

import com.example.traveling.travelshare.data.TravelShareDataProvider;
import com.example.traveling.travelshare.domain.TravelShareSessionRepository;
import com.example.traveling.travelshare.ui.TravelShareAddPostFragment;
import com.example.traveling.travelshare.ui.TravelShareAuthFragment;
import com.example.traveling.travelshare.ui.TravelShareHomeFragment;
import com.example.traveling.travelshare.ui.TravelShareItineraryFragment;
import com.example.traveling.travelshare.ui.TravelShareMessagesFragment;
import com.example.traveling.travelshare.ui.TravelSharePostDetailFragment;
import com.example.traveling.travelshare.ui.TravelShareProfileFragment;
import com.example.traveling.travelshare.ui.TravelShareSearchFragment;
import com.google.android.material.bottomnavigation.BottomNavigationView;

public class MainActivity extends AppCompatActivity {

    private TravelShareSessionRepository sessionRepository;
    private Button sessionButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        EdgeToEdge.enable(this);
        setContentView(R.layout.activity_main);

        sessionRepository = TravelShareDataProvider.sessionRepository();
        sessionButton = findViewById(R.id.travelshare_session_button);

        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.main), (v, insets) -> {
            Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
            v.setPadding(systemBars.left, systemBars.top, systemBars.right, 0);
            return insets;
        });

        sessionButton.setOnClickListener(v -> openSessionScreen());
        refreshSessionButton();

        BottomNavigationView bottomNavigationView = findViewById(R.id.travelshare_bottom_nav);
        bottomNavigationView.setOnItemSelectedListener(item -> {
            switchToTab(item.getItemId());
            return true;
        });

        if (savedInstanceState == null) {
            bottomNavigationView.setSelectedItemId(R.id.travelshare_nav_home);
        }
    }

    public void refreshSessionButton() {
        if (sessionRepository.isAuthenticated()) {
            sessionButton.setText(R.string.travelshare_auth_profile);
        } else {
            sessionButton.setText(R.string.travelshare_auth_login);
        }
    }

    public void openPostDetail(String postId) {
        getSupportFragmentManager()
                .beginTransaction()
                .replace(R.id.travelshare_fragment_container, TravelSharePostDetailFragment.newInstance(postId))
                .addToBackStack("post_detail")
                .commit();
    }

    private void openSessionScreen() {
        Fragment fragment = sessionRepository.isAuthenticated()
                ? new TravelShareProfileFragment()
                : new TravelShareAuthFragment();

        getSupportFragmentManager()
                .beginTransaction()
                .replace(R.id.travelshare_fragment_container, fragment)
                .addToBackStack("session")
                .commit();
    }

    private void switchToTab(int itemId) {
        Fragment fragment;

        if (itemId == R.id.travelshare_nav_home) {
            fragment = new TravelShareHomeFragment();
        } else if (itemId == R.id.travelshare_nav_search) {
            fragment = new TravelShareSearchFragment();
        } else if (itemId == R.id.travelshare_nav_messages) {
            fragment = new TravelShareMessagesFragment();
        } else if (itemId == R.id.travelshare_nav_add) {
            fragment = new TravelShareAddPostFragment();
        } else {
            fragment = new TravelShareItineraryFragment();
        }

        getSupportFragmentManager()
                .beginTransaction()
                .replace(R.id.travelshare_fragment_container, fragment)
                .commit();
    }
}

package com.example.traveling;

import android.os.Bundle;
import android.widget.Button;

import androidx.activity.EdgeToEdge;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.graphics.Insets;
import androidx.core.view.ViewCompat;
import androidx.core.view.WindowInsetsCompat;
import androidx.fragment.app.Fragment;

import com.example.traveling.travelshare.data.TravelShareDataProvider;
import com.example.traveling.travelshare.domain.TravelShareSessionRepository;
import com.example.traveling.travelshare.ui.TravelShareAddPostFragment;
import com.example.traveling.travelshare.ui.TravelShareAuthFragment;
import com.example.traveling.travelshare.ui.TravelShareHomeFragment;
import com.example.traveling.travelshare.ui.TravelShareItineraryFragment;
import com.example.traveling.travelshare.ui.TravelShareMessagesFragment;
import com.example.traveling.travelshare.ui.TravelSharePostDetailFragment;
import com.example.traveling.travelshare.ui.TravelShareProfileFragment;
import com.example.traveling.travelshare.ui.TravelShareSearchFragment;
import com.example.traveling.travelshare.ui.navigation.TravelShareBottomNavConfig;
import com.example.traveling.travelshare.ui.navigation.TravelShareNavItem;
import com.google.android.material.bottomnavigation.BottomNavigationView;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class MainActivity extends AppCompatActivity {

    private TravelShareSessionRepository sessionRepository;
    private Button sessionButton;
    private final Map<Integer, TravelShareNavItem> navItemsById = new HashMap<>();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        EdgeToEdge.enable(this);
        setContentView(R.layout.activity_main);

        sessionRepository = TravelShareDataProvider.sessionRepository();
        sessionButton = findViewById(R.id.travelshare_session_button);

        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.main), (v, insets) -> {
            Insets systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars());
            v.setPadding(systemBars.left, systemBars.top, systemBars.right, 0);
            return insets;
        });

        sessionButton.setOnClickListener(v -> openSessionScreen());
        refreshSessionButton();

        BottomNavigationView bottomNavigationView = findViewById(R.id.travelshare_bottom_nav);
        List<TravelShareNavItem> navItems = TravelShareBottomNavConfig.buildItems();
        TravelShareBottomNavConfig.inflateMenu(bottomNavigationView, navItems);
        navItemsById.clear();
        for (TravelShareNavItem navItem : navItems) {
            navItemsById.put(navItem.getItemId(), navItem);
        }

        bottomNavigationView.setOnItemSelectedListener(item -> {
            switchToTab(item.getItemId());
            return true;
        });

        if (savedInstanceState == null) {
            bottomNavigationView.setSelectedItemId(R.id.travelshare_nav_home);
        }
    }

    public void refreshSessionButton() {
        if (sessionRepository.isAuthenticated()) {
            sessionButton.setText(R.string.travelshare_auth_profile);
        } else {
            sessionButton.setText(R.string.travelshare_auth_login);
        }
    }

    public void openPostDetail(String postId) {
        getSupportFragmentManager()
                .beginTransaction()
                .replace(R.id.travelshare_fragment_container, TravelSharePostDetailFragment.newInstance(postId))
                .addToBackStack("post_detail")
                .commit();
    }

    private void openSessionScreen() {
        Fragment fragment = sessionRepository.isAuthenticated()
                ? new TravelShareProfileFragment()
                : new TravelShareAuthFragment();

        getSupportFragmentManager()
                .beginTransaction()
                .replace(R.id.travelshare_fragment_container, fragment)
                .addToBackStack("session")
                .commit();
    }

    private void switchToTab(int itemId) {
        TravelShareNavItem navItem = navItemsById.get(itemId);
        if (navItem == null) {
            return;
        }

        Fragment fragment = navItem.createFragment();

        getSupportFragmentManager()
                .beginTransaction()
                .replace(R.id.travelshare_fragment_container, fragment)
                .commit();
    }
}

package com.example.traveling.travelshare.data;

import com.example.traveling.travelshare.domain.TravelSharePost;
import com.example.traveling.travelshare.domain.TravelSharePostRepository;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Locale;

public class InMemoryTravelSharePostRepository implements TravelSharePostRepository {

    private final List<TravelSharePost> posts = new ArrayList<>(Arrays.asList(
            new TravelSharePost(
                    "1",
                    "Lina",
                    "Annecy",
                    "Lac turquoise au lever du soleil",
                    "Ete 2025",
                    "Bus SIBRA + 12 min a pied",
                    18,
                    3
            ),
            new TravelSharePost(
                    "2",
                    "Mehdi",
                    "Lisbonne",
                    "Tram jaune et rues pavees dans l'Alfama",
                    "Printemps 2024",
                    "Metro + tram 28",
                    42,
                    7
            ),
            new TravelSharePost(
                    "3",
                    "Camille",
                    "Tokyo",
                    "Nuit neon a Shibuya et ramen incroyable",
                    "Automne 2025",
                    "JR Yamanote - station Shibuya",
                    64,
                    12
            ),
            new TravelSharePost(
                    "4",
                    "Yanis",
                    "Marrakech",
                    "Souk colore et epices partout",
                    "Hiver 2024",
                    "Taxi depuis la medina",
                    27,
                    5
            ),
            new TravelSharePost(
                    "5",
                    "Nora",
                    "Reykjavik",
                    "Road trip volcan et cascades en Islande",
                    "Ete 2023",
                    "Location voiture 4x4 depuis Keflavik",
                    51,
                    9
            )
    ));

    @Override
    public List<TravelSharePost> getFeedPosts() {
        return new ArrayList<>(posts);
    }

    @Override
    public List<TravelSharePost> searchPosts(String query) {
        String normalizedQuery = query == null ? "" : query.trim().toLowerCase(Locale.ROOT);
        if (normalizedQuery.isEmpty()) {
            return getFeedPosts();
        }

        List<TravelSharePost> matches = new ArrayList<>();
        for (TravelSharePost post : posts) {
            String haystack = (post.getAuthorName() + " " + post.getLocationName() + " " + post.getDescription())
                    .toLowerCase(Locale.ROOT);
            if (haystack.contains(normalizedQuery)) {
                matches.add(post);
            }
        }

        return matches;
    }

    @Override
    public TravelSharePost getPostById(String postId) {
        for (TravelSharePost post : posts) {
            if (post.getId().equals(postId)) {
                return post;
            }
        }
        return null;
    }

    @Override
    public boolean toggleLike(String postId) {
        TravelSharePost post = getPostById(postId);
        if (post == null) {
            return false;
        }
        post.toggleLike();
        return post.isLikedByCurrentUser();
    }

    @Override
    public int reportPost(String postId) {
        TravelSharePost post = getPostById(postId);
        if (post == null) {
            return 0;
        }
        post.report();
        return post.getReportCount();
    }

    @Override
    public int addComment(String postId, String commentText) {
        TravelSharePost post = getPostById(postId);
        if (post == null) {
            return 0;
        }

        if (commentText != null && !commentText.trim().isEmpty()) {
            post.addComment();
        }
        return post.getCommentCount();
    }
}

package com.example.traveling.travelshare.data;

import com.example.traveling.travelshare.domain.TravelSharePost;
import com.example.traveling.travelshare.domain.TravelSharePostRepository;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Locale;

public class InMemoryTravelSharePostRepository implements TravelSharePostRepository {

    private final List<TravelSharePost> posts = new ArrayList<>(Arrays.asList(
            new TravelSharePost(
                    "1",
                    "Lina",
                    "Annecy",
                    "Lac turquoise au lever du soleil",
                    "Ete 2025",
                    "Bus SIBRA + 12 min a pied",
                    18,
                    3
            ),
            new TravelSharePost(
                    "2",
                    "Mehdi",
                    "Lisbonne",
                    "Tram jaune et rues pavees dans l'Alfama",
                    "Printemps 2024",
                    "Metro + tram 28",
                    42,
                    7
            ),
            new TravelSharePost(
                    "3",
                    "Camille",
                    "Tokyo",
                    "Nuit neon a Shibuya et ramen incroyable",
                    "Automne 2025",
                    "JR Yamanote - station Shibuya",
                    64,
                    12
            ),
            new TravelSharePost(
                    "4",
                    "Yanis",
                    "Marrakech",
                    "Souk colore et epices partout",
                    "Hiver 2024",
                    "Taxi depuis la medina",
                    27,
                    5
            ),
            new TravelSharePost(
                    "5",
                    "Nora",
                    "Reykjavik",
                    "Road trip volcan et cascades en Islande",
                    "Ete 2023",
                    "Location voiture 4x4 depuis Keflavik",
                    51,
                    9
            )
    ));

    private int nextGeneratedId = 6;

    @Override
    public List<TravelSharePost> getFeedPosts() {
        return new ArrayList<>(posts);
    }

    @Override
    public List<TravelSharePost> searchPosts(String query) {
        String normalizedQuery = query == null ? "" : query.trim().toLowerCase(Locale.ROOT);
        if (normalizedQuery.isEmpty()) {
            return getFeedPosts();
        }

        List<TravelSharePost> matches = new ArrayList<>();
        for (TravelSharePost post : posts) {
            String haystack = (post.getAuthorName() + " " + post.getLocationName() + " " + post.getDescription())
                    .toLowerCase(Locale.ROOT);
            if (haystack.contains(normalizedQuery)) {
                matches.add(post);
            }
        }

        return matches;
    }

    @Override
    public TravelSharePost getPostById(String postId) {
        for (TravelSharePost post : posts) {
            if (post.getId().equals(postId)) {
                return post;
            }
        }
        return null;
    }

    @Override
    public boolean toggleLike(String postId) {
        TravelSharePost post = getPostById(postId);
        if (post == null) {
            return false;
        }
        post.toggleLike();
        return post.isLikedByCurrentUser();
    }

    @Override
    public int reportPost(String postId) {
        TravelSharePost post = getPostById(postId);
        if (post == null) {
            return 0;
        }
        post.report();
        return post.getReportCount();
    }

    @Override
    public int addComment(String postId, String commentText) {
        TravelSharePost post = getPostById(postId);
        if (post == null) {
            return 0;
        }

        if (commentText != null && !commentText.trim().isEmpty()) {
            post.addComment();
        }
        return post.getCommentCount();
    }

    @Override
    public TravelSharePost createPost(
            String authorName,
            String locationName,
            String description,
            String period,
            String howToGetThere
    ) {
        TravelSharePost createdPost = new TravelSharePost(
                String.valueOf(nextGeneratedId++),
                authorName == null || authorName.trim().isEmpty() ? "Voyageur" : authorName.trim(),
                locationName == null ? "" : locationName.trim(),
                description == null ? "" : description.trim(),
                period == null ? "" : period.trim(),
                howToGetThere == null ? "" : howToGetThere.trim(),
                0,
                0
        );

        // Most recent publication appears first in the feed.
        posts.add(0, createdPost);
        return createdPost;
    }
}

